ps.pstext:
if !IsFeatureImplemented(FEAT_SME_F16F16) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Zn);
let d : integer = UInt(Zd::'0');

CheckStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let pairs : integer = VL DIV 32;
let operand : bits(VL) = Z{}(n);
var result0 : bits(VL);
var result1 : bits(VL);

for p = 0 to pairs-1 do
    let element1 : bits(16) = operand[(2*p+0)*:16];
    let element2 : bits(16) = operand[(2*p+1)*:16];
    let res1 : bits(32) = FPConvertSVE{32, 16}(element1, FPCR());
    let res2 : bits(32) = FPConvertSVE{32, 16}(element2, FPCR());
    result0[p*:32] = res1;
    result1[p*:32] = res2;
end;

Z{VL}(d+0) = result0;
Z{VL}(d+1) = result1;
